// Time:  O(n)
// Space: O(1)

// greedy
class Solution {
public:
    long long minimumCost(string s) {
        int64_t result = 0;
        for (int i = 0; i + 1 < size(s); ++i) {
            if (s[i] != s[i + 1]) {
                result += min(i + 1, static_cast<int>(size(s)) - (i + 1));
            }
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(1)

# greedy
class Solution(object):
    def minimumCost(self, s):
        """
        :type s: str
        :rtype: int
        """
        return sum(min(i+1, len(s)-(i+1)) for i in xrange(len(s)-1) if s[i] != s[i+1])
